import React, { useState } from "react";
import "./App.css";

export default function App() {
  const [image, setImage] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleUpload = (e) => {
    setImage(e.target.files[0]);
    setResult(null);
  };

  const handlePredict = async () => {
    if (!image) return alert("Upload image first");

    const formData = new FormData();
    formData.append("file", image);

    setLoading(true);

    try {
      const res = await fetch("http://localhost:8000/predict", {
        method: "POST",
        body: formData,
      });

      const data = await res.json();
      setResult(data);
    } catch (err) {
      alert("Backend error");
    }

    setLoading(false);
  };

  return (
    <div className="app">

      {/* HERO */}
      <section className="hero">
        <h1>🐄 Breed Identifier AI</h1>
        <p>Upload image and detect breed instantly</p>

        <div className="upload-box">
          <input type="file" onChange={handleUpload} />

          {image && (
            <img
              src={URL.createObjectURL(image)}
              alt="preview"
              className="preview"
            />
          )}

          <button onClick={handlePredict}>
            {loading ? "Processing..." : "Identify Breed"}
          </button>
        </div>

        {result && (
          <div className="result">
            <h2>Top Breed: {result.top_match}</h2>
            <p>Confidence: {result.confidence}%</p>
          </div>
        )}
      </section>

      {/* FEATURES */}
      <section className="section">
        <h2>✨ Features</h2>
        <div className="grid">
          <div className="card">⚡ Fast AI Prediction</div>
          <div className="card">🧠 Deep Learning Model</div>
          <div className="card">📊 40+ Breeds Supported</div>
        </div>
      </section>

      {/* HOW IT WORKS */}
      <section className="section">
        <h2>🚀 How It Works</h2>
        <div className="grid">
          <div className="card">1️⃣ Upload Image</div>
          <div className="card">2️⃣ AI Processing</div>
          <div className="card">3️⃣ Get Result</div>
        </div>
      </section>

      {/* ABOUT */}
      <section className="section">
        <h2>👨‍💻 About</h2>
        <p>
          This project uses ResNet-50 deep learning model trained on cattle &
          buffalo dataset to identify breeds accurately.
        </p>
      </section>

      {/* CONTACT */}
      <section className="section">
        <h2>📞 Contact</h2>
        <p>Email: your@email.com</p>
      </section>

      <footer>© 2026 Breed AI</footer>
    </div>
  );
}
